UPDATE qna_admin
SET title = #{title},
content = #{content}
WHERE qna_admin_id = #{qnaAdminId}

mapper.select:
SELECT qa.qna_admin_id AS qnaAdminId, qa.user_id AS userId, qa.admin_id AS adminId, qa.title AS title, qa.content AS content, qa.answer AS answer, qa.status AS status, qa.created_at AS createdAt, qa.answered_at AS answeredAt,
u.name AS name, u.email AS email, u.role AS role FROM qna_admin qa JOIN user u ON qa.user_id = u.user_id WHERE 1=1
AND u.role = #{role}
AND qa.status = #{status}
AND ( u.name LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') OR qa.title LIKE CONCAT('%', #{keyword}, '%') OR qa.content LIKE CONCAT('%', #{keyword}, '%') )
AND qa.created_at >= #{startDate}
AND qa.created_at <= #{endDate}
ORDER BY CASE WHEN qa.status = '대기' THEN 0 ELSE 1 END, qa.created_at DESC

SELECT user_id
FROM qna_admin
WHERE qna_admin_id = #{qnaAdminId}
